        bracketSpacing: true,
        arrowParens: "always"
      });

      // Count lines after
      const linesAfter = formattedCode.split("\n").length;

      const result = {
        originalCode: code,
        formattedCode,
        language: lang,
        linesBefore,
        linesAfter,
        success: true
      };

      return {
        content: [
