        language: input.language,
        linesBefore: input.code.split("\n").length,
        linesAfter: input.code.split("\n").length,
        success: false,
        error: errorMessage
      };

      return {
        content: [
          {
            type: "text" as const,
            text: JSON.stringify(errorResult, null, 2)
          }
        ]
      };
    }
  }
